import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import styled from 'styled-components';
import { Bug, Brain, Shield, Leaf, ArrowRight, Sparkles } from 'lucide-react';
import ImageUpload from '../components/ImageUpload';
import { predictInsect } from '../services/api';
import { toast } from 'react-toastify';

const HomeContainer = styled.div`
  min-height: calc(100vh - 70px);
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 40px 20px;

  @media (max-width: 768px) {
    padding: 20px 15px;
  }
`;

const HeroSection = styled.div`
  text-align: center;
  margin-bottom: 60px;
  max-width: 800px;
`;

const HeroTitle = styled.h1`
  font-size: 3.5rem;
  font-weight: 800;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 20px;
  line-height: 1.2;

  @media (max-width: 768px) {
    font-size: 2.5rem;
  }

  @media (max-width: 480px) {
    font-size: 2rem;
  }
`;

const HeroSubtitle = styled.p`
  font-size: 1.25rem;
  color: #666;
  margin-bottom: 30px;
  line-height: 1.6;

  @media (max-width: 768px) {
    font-size: 1.1rem;
  }
`;

const FeaturesGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 30px;
  margin-bottom: 60px;
  max-width: 1000px;
  width: 100%;
`;

const FeatureCard = styled.div`
  background: white;
  border-radius: 16px;
  padding: 30px;
  text-align: center;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1);
  transition: all 0.3s ease;

  &:hover {
    transform: translateY(-10px);
    box-shadow: 0 16px 48px rgba(0, 0, 0, 0.15);
  }
`;

const FeatureIcon = styled.div`
  width: 80px;
  height: 80px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  margin: 0 auto 20px;
  color: white;
  font-size: 32px;
`;

const FeatureTitle = styled.h3`
  font-size: 1.5rem;
  font-weight: 700;
  color: #333;
  margin-bottom: 15px;
`;

const FeatureDescription = styled.p`
  color: #666;
  line-height: 1.6;
`;

const UploadSection = styled.div`
  max-width: 600px;
  width: 100%;
  margin-bottom: 40px;
`;

const AnalyzeButton = styled.button`
  width: 100%;
  padding: 18px 30px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  border-radius: 12px;
  font-size: 18px;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.3s ease;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  margin-top: 20px;

  &:hover:not(:disabled) {
    transform: translateY(-3px);
    box-shadow: 0 12px 35px rgba(102, 126, 234, 0.4);
  }

  &:disabled {
    opacity: 0.7;
    cursor: not-allowed;
  }
`;

const StatsSection = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 30px;
  max-width: 800px;
  width: 100%;
`;

const StatCard = styled.div`
  background: white;
  border-radius: 16px;
  padding: 30px;
  text-align: center;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1);
`;

const StatNumber = styled.div`
  font-size: 2.5rem;
  font-weight: 800;
  color: #667eea;
  margin-bottom: 10px;
`;

const StatLabel = styled.div`
  font-size: 1rem;
  color: #666;
  font-weight: 600;
`;

const HomePage = () => {
  const [selectedImage, setSelectedImage] = useState(null);
  const [selectedFile, setSelectedFile] = useState(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const navigate = useNavigate();

  const handleImageSelect = (imageData, file) => {
    setSelectedImage(imageData);
    setSelectedFile(file);
  };

  const handleImageRemove = () => {
    setSelectedImage(null);
    setSelectedFile(null);
  };

  const handleAnalyze = async () => {
    if (!selectedFile) {
      toast.error('Vui lòng chọn ảnh trước khi phân tích');
      return;
    }

    setIsAnalyzing(true);
    try {
      const result = await predictInsect(selectedFile);

      // Lưu kết quả vào localStorage để truyền sang ResultPage
      localStorage.setItem('analysisResult', JSON.stringify({
        image: selectedImage,
        predictions: result.predictions,
        timestamp: new Date().toISOString()
      }));

      navigate('/result');
    } catch (error) {
      console.error('Lỗi khi phân tích:', error);
      toast.error('Có lỗi xảy ra khi phân tích ảnh. Vui lòng thử lại.');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <HomeContainer>
      <HeroSection>
        <HeroTitle>
          NhanDienSauHai
          <br />
          <span style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px' }}>
            Bằng AI <Sparkles size={40} />
          </span>
        </HeroTitle>
        <HeroSubtitle>
          Ứng dụng thông minh giúp nông dân nhận diện và xử lý sâu bệnh/côn trùng gây hại 
          một cách nhanh chóng và chính xác
        </HeroSubtitle>
      </HeroSection>

      <FeaturesGrid>
        <FeatureCard>
          <FeatureIcon>
            <Brain size={40} />
          </FeatureIcon>
          <FeatureTitle>AI Thông Minh</FeatureTitle>
          <FeatureDescription>
            Sử dụng công nghệ YOLOv8 tiên tiến để nhận diện chính xác 102 loài côn trùng gây hại
          </FeatureDescription>
        </FeatureCard>

        <FeatureCard>
          <FeatureIcon>
            <Shield size={40} />
          </FeatureIcon>
          <FeatureTitle>Thông Tin Chi Tiết</FeatureTitle>
          <FeatureDescription>
            Cung cấp thông tin đầy đủ về mức độ nguy hiểm, cách phòng và chữa trị
          </FeatureDescription>
        </FeatureCard>

        <FeatureCard>
          <FeatureIcon>
            <Leaf size={40} />
          </FeatureIcon>
          <FeatureTitle>Thân Thiện Môi Trường</FeatureTitle>
          <FeatureDescription>
            Khuyến khích sử dụng phương pháp sinh học, hạn chế thuốc hóa học
          </FeatureDescription>
        </FeatureCard>
      </FeaturesGrid>

      <UploadSection>
        <ImageUpload
          onImageSelect={handleImageSelect}
          onImageRemove={handleImageRemove}
          selectedImage={selectedImage}
        />

        <AnalyzeButton
          onClick={handleAnalyze}
          disabled={!selectedImage || isAnalyzing}
        >
          {isAnalyzing ? (
            <>
              <div className="spinner"></div>
